import{_ as a,H as o,f as r,b as e,j as P}from"./chunks/framework.DLd0CbzH.js";const T=JSON.parse('{"title":"WPS/PPT 后期排版标准化","description":"","frontmatter":{"title":"WPS/PPT 后期排版标准化","category":"PPT 技巧","excerpt":"1、解决PPT页面高度不一致的问题 2、消除PPT页面中背景虚线网格问题","source":"1. 解决页面高度不一致（核心痛点） 统一画布：设计 -> 幻灯片大小 -> 宽屏 16:9。 内容对齐： 铺满法：选中背景块，取消“锁定纵横比”，手动向上/下拉伸至贴合幻灯片边缘。 缩减法：选中第一页全屏图，输入第二页内容块的精确高度数值（如 16.5cm），然后执行 垂直居中。 视觉统一：右键背景 -> 设置背景格式 -> 使用吸管吸取内容块颜色，点击 全部应用。  2. 消除背景虚线/网格 检查视图：视图 -> 取消勾选 网格线（确认是否为辅助线）。  覆盖大法：在内容块下方垫一个同色的纯色矩形，或对背景图进行微弱的“模糊”处理（1-2 像素）。","cover":"/media/images/covers/tools-ppt-008-WPS-PPT-后期排版标准化.jpg"},"headers":[],"relativePath":"tools/ppt/008-WPS-PPT-后期排版标准化.md","filePath":"tools/ppt/008-WPS-PPT-后期排版标准化.md"}'),s={name:"tools/ppt/008-WPS-PPT-后期排版标准化.md"};function l(p,t,n,c,i,_){return o(),r("div",null,[...t[0]||(t[0]=[e("h1",{id:"wps-ppt-后期排版标准化",tabindex:"-1"},[P("WPS/PPT 后期排版标准化 "),e("a",{class:"header-anchor",href:"#wps-ppt-后期排版标准化","aria-label":'Permalink to "WPS/PPT 后期排版标准化"'},"​")],-1),e("p",null,"1、解决PPT页面高度不一致的问题 2、消除PPT页面中背景虚线网格问题",-1),e("p",null,[e("strong",null,"来源："),P(" 1. 解决页面高度不一致（核心痛点） 统一画布：设计 -> 幻灯片大小 -> 宽屏 16:9。 内容对齐： 铺满法：选中背景块，取消“锁定纵横比”，手动向上/下拉伸至贴合幻灯片边缘。 缩减法：选中第一页全屏图，输入第二页内容块的精确高度数值（如 16.5cm），然后执行 垂直居中。 视觉统一：右键背景 -> 设置背景格式 -> 使用吸管吸取内容块颜色，点击 全部应用。")],-1),e("ol",{start:"2"},[e("li",null,"消除背景虚线/网格 检查视图：视图 -> 取消勾选 网格线（确认是否为辅助线）。")],-1),e("p",null,"覆盖大法：在内容块下方垫一个同色的纯色矩形，或对背景图进行微弱的“模糊”处理（1-2 像素）。",-1)])])}const m=a(s,[["render",l]]);export{T as __pageData,m as default};
